#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int Min(int x,int y){return x<y?x:y;}
const int N=2e5+10,Sz=(1<<15)-1;
int num[20],a[N],mxn[Sz+10],sum[Sz+10];int ans,S;
int main()
{
	int n=read();rep(2,n,i){int x=read()+1,y=read()+1,z=read();a[x]^=z;a[y]^=z;}
	rep(1,n,i)++num[a[i]];rep(1,15,i){ans+=(num[i]>>1);if(num[i]&1)S|=(1<<(i-1));}
	mxn[0]=-1;rep(1,Sz,i)
	{
		mxn[i]=mxn[i>>1]+(i&1);
		rep(1,15,j)if((1<<(j-1))&i)sum[i]^=j;
	}mxn[0]=0;
	rep(1,Sz,i)if(!sum[i])for(int j=(i-1)&i;j;j=(j-1)&i)if(!sum[j])mxn[i]=Min(mxn[i],mxn[j]+mxn[i^j]);
	printf("%d\n",ans+mxn[S]);return 0;
}
